function mergeCustomsLabels(raw: Partial<InvoiceCustomsStyleLabels> | undefined): InvoiceCustomsStyleLabels {
  return { ...INVOICE_CUSTOMS_LABEL_DEFAULTS, ...(raw || {}) };
}

function mergeInvoiceWelteTrade(raw: Partial<InvoiceWelteTradeBlock> | undefined): InvoiceWelteTradeBlock {
  const r = raw || {};
  const merged: InvoiceWelteTradeBlock = { ...createDefaultInvoiceWelteTrade(), ...r };
  merged.customsLabels = mergeCustomsLabels(r.customsLabels);
  return merged;
}

/** dd/mm/yyyy — customs-style sheet date format. */
function formatWelteDate(ms: number | undefined): string {
  if (ms === undefined || ms === null || !Number.isFinite(ms) || ms <= 0) return '';
  const d = new Date(ms);
  const dd = String(d.getDate()).padStart(2, '0');
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const yyyy = d.getFullYear();
  return `${dd}/${mm}/${yyyy}`;
}

function normalizeInvoiceExtraCharges(raw: unknown): InvoiceExtraCharge[] {
  if (!Array.isArray(raw)) return [];
  return raw
    .filter((x: unknown): x is Record<string, unknown> => !!x && typeof x === 'object')
    .map((x, i) => ({
      id: String(x.id ?? `ec-${i}-${Date.now()}`),
      label: typeof x.label === 'string' ? x.label : '',
      amount: Math.max(0, Number(x.amount) || 0),
      enabled: Boolean(x.enabled)
    }));
}

function sumEnabledInvoiceExtras(charges: InvoiceExtraCharge[]): number {
  return charges
    .filter((c) => c.enabled && (c.label || '').trim() && (Number(c.amount) || 0) > 0)
    .reduce((s, c) => s + Math.max(0, Number(c.amount) || 0), 0);
}

function getSupplierDisplayName(s: Pick<Supplier, 'name' | 'firstName' | 'lastName' | 'companyName'>): string {
  const comp = (s.companyName ?? '').trim();
  if (comp) return comp;
  const person = `${(s.firstName ?? '').trim()} ${(s.lastName ?? '').trim()}`.trim();
  if (person) return person;
  const legacy = (s.name ?? '').trim();
  return legacy || 'Supplier';
}

