// --- UTILITY FUNCTIONS ---
const normalizeDigits = (str: string | number): string => {
  if (str === null || str === undefined) return '';
  return str.toString()
    .replace(/[۰٠]/g, '0').replace(/[۱١]/g, '1').replace(/[۲٢]/g, '2')
    .replace(/[۳٣]/g, '3').replace(/[۴٤]/g, '4').replace(/[۵٥]/g, '5')
    .replace(/[۶٦]/g, '6').replace(/[۷٧]/g, '7').replace(/[۸٨]/g, '8').replace(/[۹٩]/g, '9');
};

const formatNumber = (num: number | string): string => {
  if (num === '' || num === null || isNaN(Number(num)) || num === 0) return '';
  const n = Number(num);
  const str = n.toString();
  const dot = str.indexOf('.');
  if (dot === -1) return str.replace(/\B(?=(\d{3})+(?!\d))/g, ',');
  return str.slice(0, dot).replace(/\B(?=(\d{3})+(?!\d))/g, ',') + str.slice(dot);
};

const parseInput = (val: string): number => {
  const clean = normalizeDigits(val).replace(/,/g, '');
  const parsed = parseFloat(clean);
  return isNaN(parsed) ? 0 : parsed;
};

/** Full number with grouping (including 0); used for blur / display sync in numeric inputs. */
const formatWithSeparators = (n: number): string => {
  if (!Number.isFinite(n)) return '';
  const neg = n < 0 || Object.is(n, -0);
  const str = Math.abs(n).toString();
  const dot = str.indexOf('.');
  if (dot === -1) return (neg ? '-' : '') + str.replace(/\B(?=(\d{3})+(?!\d))/g, ',');
  const intPart = str.slice(0, dot);
  const dec = str.slice(dot);
  return (neg ? '-' : '') + intPart.replace(/\B(?=(\d{3})+(?!\d))/g, ',') + dec;
};

/** Formats raw keystrokes with comma grouping while preserving an in-progress decimal point. */
const formatThousandsWhileTyping = (raw: string, integerOnly?: boolean): string => {
  let s = normalizeDigits(raw).replace(/,/g, '').trim();
  if (s === '') return '';

  let neg = false;
  if (s.startsWith('-')) {
    neg = true;
    s = s.slice(1);
  }

  const buf: string[] = [];
  let dotSeen = false;
  for (let i = 0; i < s.length; i++) {
    const ch = s[i];
    if (ch >= '0' && ch <= '9') buf.push(ch);
    else if (!integerOnly && ch === '.' && !dotSeen) {
      buf.push('.');
      dotSeen = true;
    }
  }
  s = buf.join('');
  if (s === '') return neg ? '-' : '';
  if (s === '.') return neg ? '-.' : '.';

  const dotIdx = s.indexOf('.');
  if (dotIdx === -1) {
    const formatted = s.replace(/\B(?=(\d{3})+(?!\d))/g, ',');
    return (neg ? '-' : '') + formatted;
  }

  const intRaw = s.slice(0, dotIdx);
  const fracRaw = s.slice(dotIdx + 1);
  const intFormatted = intRaw ? intRaw.replace(/\B(?=(\d{3})+(?!\d))/g, ',') : '';
  const sign = neg ? '-' : '';
  if (intRaw === '') {
    if (fracRaw === '') return `${sign}.`;
    return `${sign}.${fracRaw}`;
  }
  if (fracRaw === '' && s.endsWith('.')) return `${sign}${intFormatted}.`;
  return `${sign}${intFormatted}.${fracRaw}`;
};

const formatMoney = (amount: number, currency: string): string => {
  const decimals = currency === 'OMR' ? 3 : 2;
  return new Intl.NumberFormat('en-US', { 
    style: 'currency', 
    currency: currency || 'USD',
    minimumFractionDigits: decimals, 
    maximumFractionDigits: decimals 
  }).format(amount);
};

const stripUndefinedDeep = (value: any): any => {
  if (Array.isArray(value)) {
    return value.map(stripUndefinedDeep);
  }

  if (value && typeof value === 'object') {
    const cleaned: Record<string, any> = {};
    for (const [key, val] of Object.entries(value)) {
      if (val !== undefined) {
        cleaned[key] = stripUndefinedDeep(val);
      }
    }
    return cleaned;
  }

  return value;
};

const withTimeout = async <T,>(promise: Promise<T>, ms = 15000, label = 'Operation'): Promise<T> => {
  return new Promise<T>((resolve, reject) => {
    const timer = setTimeout(() => {
      reject(new Error(`${label} timed out. Check internet connection and Firebase access.`));
    }, ms);

    promise
      .then((result) => {
        clearTimeout(timer);
        resolve(result);
      })
      .catch((error) => {
        clearTimeout(timer);
        reject(error);
      });
  });
};

/** Random id for catalog short links (Firestore doc id under `catalog_short_links`). */
const generateCatalogShortCode = (len = 10): string => {
  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnpqrstuvwxyz23456789';
  let s = '';
  for (let i = 0; i < len; i++) s += chars[Math.floor(Math.random() * chars.length)];
  return s;
};

const isIOSDevice = (): boolean => {
    if (typeof navigator === 'undefined') return false;
    const ua = navigator.userAgent || '';
    if (/iPhone|iPad|iPod/i.test(ua)) return true;
    return navigator.platform === 'MacIntel' && (navigator as any).maxTouchPoints > 1;
};

const isAndroidDevice = (): boolean => {
    if (typeof navigator === 'undefined') return false;
    return /Android/i.test(navigator.userAgent || '');
};

const triggerPrint = (): void => {
    if (typeof window === 'undefined') return;

    if (isIOSDevice()) {
        try {
            setTimeout(() => {
                try {
                    window.print();
                } catch (e) {
                    console.error('iOS print failed', e);
                    alert('To print on iPhone: tap the Share icon in Safari, then choose "Print".');
                }
            }, 100);
            return;
        } catch (e) {
            console.error('iOS print scheduling failed', e);
        }
    }

    if (isAndroidDevice()) {
        try {
            const docHtml = document.documentElement.outerHTML;
            const printWindow = window.open('', '_blank');
            if (!printWindow) {
                alert('Please allow pop-ups, or use Chrome menu > Share > Print.');
                return;
            }
            printWindow.document.open();
            printWindow.document.write(docHtml);
            printWindow.document.close();
            printWindow.addEventListener('load', () => {
                setTimeout(() => {
                    try {
                        printWindow.focus();
                        printWindow.print();
                    } catch (e) {
                        console.error('Android print failed', e);
                    }
                }, 400);
            });
            return;
        } catch (e) {
            console.error('Android print fallback failed', e);
        }
    }

    try {
        window.print();
    } catch (e) {
        console.error('window.print failed', e);
        alert('Print is not available in this browser. Use the browser menu > Print.');
    }
};

const SKU_PREFIX = 'SKU';

const formatSku = (n: number): string => `${SKU_PREFIX}-${String(n).padStart(4, '0')}`;

const nextSkuNumber = (products: { sku?: string }[]): number => {
    let max = 0;
    products.forEach(p => {
        if (!p.sku) return;
        const m = p.sku.match(/(\d+)\s*$/);
        if (m) {
            const n = parseInt(m[1], 10);
            if (!isNaN(n) && n > max) max = n;
        }
    });
    return max + 1;
};

const ensureSkus = <T extends { sku?: string }>(products: T[]): T[] => {
    let nextNum = nextSkuNumber(products);
    return products.map(p => {
        if (p.sku && p.sku.trim().length > 0) return p;
        const sku = formatSku(nextNum);
        nextNum += 1;
        return { ...p, sku };
    });
};

