      const p = logisticsPresets.find((x) => x.id === id);
      if (!p) return;
      if (!window.confirm(`حذف الگوی «${p.name}»؟`)) return;
      setLogisticsPresets((prev) => prev.filter((x) => x.id !== id));
      setLogisticsPresetPickerKey((k) => k + 1);
